'use client'

import { useCallback, useRef } from 'react'
import { AgGridReact } from 'ag-grid-react'
import type { ColDef, GridReadyEvent, RowClickedEvent, SelectionChangedEvent } from 'ag-grid-community'

import 'ag-grid-community/styles/ag-grid.css'
import 'ag-grid-community/styles/ag-theme-alpine.css'

interface DataTableProps<T> {
    columnDefs: ColDef<T>[]
    rowData: T[]
    onRowClick?: (row: T) => void
    onSelectionChange?: (rows: T[]) => void
    loading?: boolean
    height?: number
}

export function DataTable<T>({
    columnDefs,
    rowData,
    onRowClick,
    onSelectionChange,
    loading = false,
    height = 500,
}: DataTableProps<T>) {
    const gridRef = useRef<AgGridReact<T>>(null)

    const defaultColDef: ColDef = {
        sortable: true,
        resizable: true,
    }

    const onRowClickedHandler = useCallback(
        (event: RowClickedEvent<T>) => {
            if (onRowClick && event.data) {
                onRowClick(event.data)
            }
        },
        [onRowClick]
    )

    const onSelectionChangedHandler = useCallback(
        (event: SelectionChangedEvent<T>) => {
            if (onSelectionChange) {
                const selected = event.api.getSelectedRows()
                onSelectionChange(selected)
            }
        },
        [onSelectionChange]
    )

    const onGridReady = useCallback((_event: GridReadyEvent) => {
        // grid ready
    }, [])

    return (
        <div className="ag-theme-alpine" style={{ height, width: '100%' }}>
            <AgGridReact<T>
                ref={gridRef}
                columnDefs={columnDefs}
                rowData={rowData}
                defaultColDef={defaultColDef}
                rowSelection="single"
                pagination={true}
                paginationPageSize={20}
                loading={loading}
                overlayNoRowsTemplate="<span>데이터가 없습니다</span>"
                onRowClicked={onRowClickedHandler}
                onSelectionChanged={onSelectionChangedHandler}
                onGridReady={onGridReady}
            />
        </div>
    )
}

